import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

// Pages
import Home from "./pages/Home";
import ListingPage from "./pages/ListingPage";
import BookingConfirmation from "./pages/BookingConfirmation";
import Experience from "./pages/Experience";
import Login from "./pages/Login";
import Signup from "./pages/Signup";

// Components
import ListingList from "./components/ListingList";
import ListingDetail from "./components/ListingDetail";

// Example Header/Navbar (optional)
function Header() { return <h1>Airbnb Clone</h1>; }
function Navbar() { return <nav>Navbar Links</nav>; }

function App() {
  const [selectedListing, setSelectedListing] = useState(null);

  // Dummy listings
  const listings = [
    { id: 1, title: "Cozy Apartment", location: "Delhi", price: 150, guests: 2 },
    { id: 2, title: "Beach House", location: "Goa", price: 300, guests: 4 },
    { id: 3, title: "Mountain Cabin", location: "Manali", price: 250, guests: 3 },
  ];

  return (
    <Router>
      <Header />
      <Navbar />

      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/listingpage" element={<ListingPage />} />
        <Route path="/booking" element={<BookingConfirmation />} />
        <Route path="/experience" element={<Experience />} />
        <Route path="/login" element={<Login />} />
        <Route path="/signup" element={<Signup />} />
      </Routes>

      {/* Show listing list */}
      <ListingList listings={listings} onSelect={setSelectedListing} />

      {/* Show detail of selected listing */}
      {selectedListing && <ListingDetail listing={selectedListing} />}
    </Router>
  );
}

export default App;
